import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { Container, Row, Col, Button, Spinner, Card } from 'react-bootstrap';
import api from '../services/api';
import '../styles/card.css';

function EventDetailPage() {
  const { id } = useParams();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchEventDetail = async () => {
      try {
        const response = await api.get(`/events/${id}`);
        setEvent(response.data);
      } catch (err) {
        console.error('Lỗi khi tải chi tiết sự kiện:', err);
      } finally {
        setLoading(false);
      }
    };
    fetchEventDetail();
  }, [id]);

  if (loading) return (
    <div className="d-flex justify-content-center align-items-center" style={{ minHeight: '80vh' }}>
      <Spinner animation="border" variant="dark" />
    </div>
  );

  if (!event) return (
    <Container className="mt-5 text-center">
      <h3>Rất tiếc, không tìm thấy sự kiện này.</h3>
    </Container>
  );

  const eventDate = new Date(event.event_date);

  return (
    <Container fluid className="py-5 px-lg-5" style={{ minHeight: '100vh' }}>
      <Row className="justify-content-center">
        <Col xs={12} xl={11}>
          <Card className="ticket-detail-card shadow-lg border-0">
            
            {/* CẤU TRÚC ĐỤC LỖ VÀ NÉT ĐỨT (ABSOLUTE LAYOUT) */}
            <div className="ticket-punch-line">
              <div id="circle1" className="circle"></div>
              <div id="circle2" className="circle"></div>
              <svg width="4" height="415" viewBox="0 0 4 415" fill="none" xmlns="http://www.w3.org/2000/svg" id="vertical-dashed">
                <path 
                  stroke="#27272A" 
                  strokeWidth="4" 
                  strokeLinecap="round" 
                  strokeDasharray="4 12" 
                  d="M2 2v411"
                ></path>
              </svg>
            </div>

            <Row className="g-0 align-items-stretch">
              {/* PHẦN THÔNG TIN VÉ (CHIẾM 5/12 CỘT ~ 41.6%) */}
              <Col md={4} className="d-flex">
                <div className="ticket-body w-100">
                  <div className="mb-auto">
                    <h1 className="ticket-event-title text-uppercase">{event.title}</h1>
                    <p className="fs-5 text-muted">Sự kiện bởi {event.artist_name || 'Ban tổ chức'}</p>

                    <div className="ticket-info-list">
                      <div className="info-item">
                        <div className="ticket-label">Ngày & Giờ</div>
                        <div className="ticket-value">
                          <i className="fa-regular fa-calendar-check me-2"></i>
                          {eventDate.toLocaleDateString('vi-VN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                          <br />
                          <i className="fa-regular fa-clock me-2 mt-2"></i>
                          {eventDate.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}
                        </div>
                      </div>

                      <div className="info-item">
                        <div className="ticket-label">Địa điểm</div>
                        <div className="ticket-value">
                          <i className="fa-solid fa-location-dot me-2 text-danger"></i>
                          {event.location}
                        </div>
                      </div>

                      <div className="info-item">
                        <div className="ticket-label">Giá vé hiện tại</div>
                        <div className="ticket-value price-text">
                          {event.price ? `${event.price.toLocaleString('vi-VN')} VND` : 'Miễn phí'}
                        </div>
                      </div>
                    </div>
                  </div>

                  <Button className="btn-buy-ticket-large w-100 shadow-sm">
                    MUA VÉ NGAY
                  </Button>
                </div>
              </Col>

              {/* PHẦN BANNER ẢNH (CHIẾM 7/12 CỘT ~ 58.4%) */}
              <Col md={8}>
                <div className="ticket-image-wrapper">
                  <img 
                    src={event.banner_image ? require(`../assets/images/${event.banner_image}`) : 'https://via.placeholder.com/1200x800'} 
                    alt={event.title} 
                    className="img-main-ticket"
                  />
                </div>
              </Col>
            </Row>
          </Card>

          {/* PHẦN MÔ TẢ PHỤ PHÍA DƯỚI VÉ */}
          <div className="mt-5 px-2">
            <h3 className="fw-bold mb-4" style={{ borderLeft: '5px solid #000', paddingLeft: '15px' }}>
              Chi tiết sự kiện
            </h3>
            <div className="p-4 bg-white rounded-4 shadow-sm" style={{ fontSize: '1.1rem', color: '#444', lineHeight: '1.8' }}>
              {event.description}
            </div>
          </div>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
